content.problemStatement:
What will be the output of the following C++ code?

```cpp
#include 
using namespace std;

int main() {
    int num = 25;
    int* ptr1 = &num;   // Pointer ptr1 points to num
    int** ptr2 = &ptr1;  // Pointer to pointer ptr2 points to ptr1

    cout << "Address stored in ptr1: " << ptr1 << endl;  // Prints the address stored in ptr1
    cout << "Address stored in ptr2: " << ptr2 << endl;  // Prints the address stored in ptr2

    return 0;
}
```

